def strat(df):
    lookback = 5  # weekly bars approximated as 5 trading days
    entry_threshold = 0.10  # 10% momentum threshold
    stop_loss = 0.10        # 10% stop loss
    take_profit = 0.40      # 40% take profit

    close = df['Close']
    n = len(df)

    momentum = (close - close.shift(lookback)) / close.shift(lookback)

    positions = pd.Series(0, index=df.index)

    in_trade = False
    entry_price = 0.0

    for i in range(n):
        if not in_trade:
            if i >= lookback:
                mom = momentum.iloc[i]
                if pd.notna(mom) and mom > entry_threshold:
                    in_trade = True
                    entry_price = close.iloc[i]
                    positions.iloc[i] = 1
                else:
                    positions.iloc[i] = 0
            else:
                positions.iloc[i] = 0
        else:
            current_price = close.iloc[i]
            pnl = (current_price - entry_price) / entry_price

            if pnl <= -stop_loss or pnl >= take_profit:
                in_trade = False
                entry_price = 0.0
                positions.iloc[i] = 0
            else:
                positions.iloc[i] = 1

    return positions
